mapper.insert:
INSERT INTO account_transactions (
    account_id, member_id, transfer_id, request_no, transaction_type,
    amount, balance_after, description
) VALUES (
    #{accountId}, #{memberId}, #{transferId}, #{requestNo}, #{transactionType},
    #{amount}, #{balanceAfter}, #{description}
)

mapper.select:
SELECT
    id, account_id, member_id, transfer_id, request_no, transaction_type,
    amount, balance_after, description, created_at
FROM account_transactions
WHERE transfer_id = #{transferId}
  AND transaction_type = #{transactionType}

SELECT atr.id AS transaction_id, atr.transaction_type, atr.amount, atr.balance_after, atr.description, atr.created_at, t.transfer_no, from_account.account_number AS from_account_number, to_account.account_number AS to_account_number FROM account_transactions atr LEFT JOIN transfers t ON atr.transfer_id = t.id LEFT JOIN accounts from_account ON t.from_account_id = from_account.id LEFT JOIN accounts to_account ON t.to_account_id = to_account.id WHERE atr.account_id = #{accountId} AND atr.transaction_type IN
#{type}
AND atr.created_at >= #{fromCreatedAt} AND atr.created_at < #{toCreatedAtExclusive}
AND ( atr.created_at < #{cursorCreatedAt} OR (atr.created_at = #{cursorCreatedAt} AND atr.id < #{cursorId}) )
ORDER BY atr.created_at DESC, atr.id DESC LIMIT #{limit}
